const { Readable, PassThrough } = require("node:stream");

module.exports = async function probe() {
    const items = [];
    const readable = Readable.from(["alpha", "beta", "gamma"]);
    for await (const chunk of readable) {
        items.push(chunk);
    }

    const pass = new PassThrough();
    const collected = [];
    pass.on("data", (chunk) => collected.push(String(chunk)));
    pass.write("hello");
    pass.write("-");
    pass.write("stream");
    pass.end();
    await pass.finished;

    return {
        readable: items.join(","),
        passThrough: collected.join(""),
    };
};
